VALUES
  ('social-worker-moex-01001', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年性剝削防制條例，關於安置及服務之內容，下列何者錯誤？', '["檢察官、司法警察官及司法警察查獲及救援被害人後，應於 24 小時內將被害人交由當地直轄 市、縣（市）主管機關處理", "直轄市、縣（市）主管機關若依法緊急安置被害人，應於安置起1週內，評估有無繼續安置之 必要，經評估有安置必要者，應提出報告，聲請法院裁定", "兒童或少年遭受性剝削或有遭受性剝削之虞者，如無另犯其他之罪，不適用少年事件處理法及 社會秩序維護法規定", "直轄市、縣（市）主管機關得令被害人之父母、監護人或其他實際照顧之人接受8小時以上50 小時以下之親職教育輔導，並得實施家庭處遇計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01002', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年性剝削防制條例，關於中途學校之設置，下列敘述何者正確？', '["中途學校應聘請社會工作、心理、輔導及教育等專業人員，並結合民間資源，提供選替教育及 輔導", "中途學校之設立與員額編制準則，由法務部定之", "安置對象逾國民教育階段者，中途學校不得提供其繼續教育", "中途學校學生之畢業證書應由該中途學校獨立頒發"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01003', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬於特殊境遇家庭扶助條例所定之特殊境遇家庭扶助項目？', '["求職交通補助", "創業貸款補助", "法律訴訟補助", "緊急生活扶助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01004', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於性侵害犯罪防治法之立法意旨及主管機關業務劃分，下列敘述何者錯誤？', '["為防治性侵害犯罪及保護被害人權益，因而制定性侵害犯罪防治法", "中央主管機關應研擬性侵害防治政策並推展性侵害防治教育", "社政主管機關應主責各級學校性侵害防治教育、性侵害被害人及其子女就學權益之維護等相關 事宜", "直轄市、縣（市）主管機關應設性侵害防治中心並提供被害人24小時緊急救援"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01005', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '精神衛生法中，關於精神衛生體系的敘述，下列何者錯誤？', '["各級社政主管機關應規劃、推動與協助病人，接受各級各類教育及建立友善支持學習環境", "勞工主管機關應推動職場心理衛生，協助病情穩定之病人接受職業訓練及就業服務，並獎勵或 補助雇主提供其就業機會", "直轄市、縣（市）主管機關應由社區心理衛生中心，辦理心理衛生宣導、教育訓練及其他心理 衛生等事項", "中央主管機關應會同中央社政、勞工及教育主管機關建立社區照顧、支持與復健體系"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01006', 'social-worker', 'social-worker-moex-111-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法，有關身心障礙者申請鑑定之相關規定，下列何者錯誤？', '["由專業團隊鑑定及評估，專業人員包括醫事、社工、特殊教育及職業輔導評量的專家", "鑑定報告，至遲應於完成後7日送達申請人戶籍所在地的衛生主管機關", "身心障礙鑑定之項目，符合全民健康保險法規定給付者，應以保險支付", "身心障礙類別之程度分級、鑑定向度及基準、鑑定方法、工具及作業方式，由中央衛生主管機 關定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "df723dff4b1e", "answer_pdf_sha1": "daf7b0bf0c47", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
